void DetectionByTracker::onObjects(
  const tier4_perception_msgs::msg::DetectedObjectsWithFeature::ConstSharedPtr input_msg)
{
  debugger_->startMeasureProcessingTime();
  autoware_perception_msgs::msg::DetectedObjects detected_objects;
  detected_objects.header = input_msg->header;

  // get objects from tracking module
  autoware_perception_msgs::msg::DetectedObjects tracked_objects;
  {
    autoware_perception_msgs::msg::TrackedObjects objects, transformed_objects;
    const bool available_trackers =
      tracker_handler_.estimateTrackedObjects(input_msg->header.stamp, objects);
    if (
      !available_trackers ||
      !autoware::object_recognition_utils::transformObjects(
        objects, input_msg->header.frame_id, tf_buffer_, transformed_objects)) {
      objects_pub_->publish(detected_objects);
      published_time_publisher_->publish_if_subscribed(objects_pub_, detected_objects.header.stamp);
      return;
    }
    // to simplify post processes, convert tracked_objects to DetectedObjects message.
    tracked_objects = autoware::object_recognition_utils::toDetectedObjects(transformed_objects);
  }
  debugger_->publishInitialObjects(*input_msg);
  debugger_->publishTrackedObjects(tracked_objects);

  // merge over segmented objects
  tier4_perception_msgs::msg::DetectedObjectsWithFeature merged_objects;
  autoware_perception_msgs::msg::DetectedObjects no_found_tracked_objects;
  mergeOverSegmentedObjects(tracked_objects, *input_msg, no_found_tracked_objects, merged_objects);
  debugger_->publishMergedObjects(merged_objects);

  // divide under segmented objects
  tier4_perception_msgs::msg::DetectedObjectsWithFeature divided_objects;
  autoware_perception_msgs::msg::DetectedObjects temp_no_found_tracked_objects;
  divideUnderSegmentedObjects(
    no_found_tracked_objects, *input_msg, temp_no_found_tracked_objects, divided_objects);
  debugger_->publishDividedObjects(divided_objects);

  // merge under/over segmented objects to build output objects
  for (const auto & merged_object : merged_objects.feature_objects) {
    detected_objects.objects.push_back(merged_object.object);
  }
  for (const auto & divided_object : divided_objects.feature_objects) {
    detected_objects.objects.push_back(divided_object.object);
  }

  objects_pub_->publish(detected_objects);
  published_time_publisher_->publish_if_subscribed(objects_pub_, detected_objects.header.stamp);
  debugger_->publishProcessingTime();
}

bool TrackerHandler::estimateTrackedObjects(
  const rclcpp::Time & time, autoware_perception_msgs::msg::TrackedObjects & output)
{
  if (objects_buffer_.empty()) {
    return false;
  }

  // Get the objects closest to the target time.
  const auto target_objects_iter = std::min_element(
    objects_buffer_.cbegin(), objects_buffer_.cend(),
    [&time](
      autoware_perception_msgs::msg::TrackedObjects first,
      autoware_perception_msgs::msg::TrackedObjects second) {
      return std::fabs((time - first.header.stamp).seconds()) <
             std::fabs((time - second.header.stamp).seconds());
    });

  // Estimate the pose of the object at the target time
  const auto dt = time - target_objects_iter->header.stamp;
  output.header.frame_id = target_objects_iter->header.frame_id;
  output.header.stamp = time;
  for (const auto & object : target_objects_iter->objects) {
    const auto & pose_with_covariance = object.kinematics.pose_with_covariance;
    const auto & x = pose_with_covariance.pose.position.x;
    const auto & y = pose_with_covariance.pose.position.y;
    const auto & z = pose_with_covariance.pose.position.z;
    const float yaw = tf2::getYaw(pose_with_covariance.pose.orientation);
    const auto & twist = object.kinematics.twist_with_covariance.twist;
    const float & vx = twist.linear.x;
    const float & wz = twist.angular.z;

    // build output
    autoware_perception_msgs::msg::TrackedObject estimated_object;
    estimated_object.object_id = object.object_id;
    estimated_object.existence_probability = object.existence_probability;
    estimated_object.classification = object.classification;
    estimated_object.shape = object.shape;
    estimated_object.kinematics.pose_with_covariance.pose.position.x =
      x + vx * std::cos(yaw) * dt.seconds();
    estimated_object.kinematics.pose_with_covariance.pose.position.y =
      y + vx * std::sin(yaw) * dt.seconds();
    estimated_object.kinematics.pose_with_covariance.pose.position.z = z;
    const float yaw_hat = autoware_utils::normalize_radian(yaw + wz * dt.seconds());
    estimated_object.kinematics.pose_with_covariance.pose.orientation =
      autoware_utils::create_quaternion_from_yaw(yaw_hat);
    output.objects.push_back(estimated_object);
  }
  return true;
}

bool transformObjects(
  const T & input_msg, const std::string & target_frame_id, const tf2_ros::Buffer & tf_buffer,
  T & output_msg)
{
  output_msg = input_msg;

  // transform to world coordinate
  if (input_msg.header.frame_id != target_frame_id) {
    output_msg.header.frame_id = target_frame_id;
    tf2::Transform tf_target2objects_world;
    tf2::Transform tf_target2objects;
    tf2::Transform tf_objects_world2objects;
    {
      const auto ros_target2objects_world = detail::getTransform(
        tf_buffer, input_msg.header.frame_id, target_frame_id, input_msg.header.stamp);
      if (!ros_target2objects_world) {
        return false;
      }
      tf2::fromMsg(*ros_target2objects_world, tf_target2objects_world);
    }
    for (auto & object : output_msg.objects) {
      auto & pose_with_cov = object.kinematics.pose_with_covariance;
      tf2::fromMsg(pose_with_cov.pose, tf_objects_world2objects);
      tf_target2objects = tf_target2objects_world * tf_objects_world2objects;
      // transform pose, frame difference and object pose
      tf2::toMsg(tf_target2objects, pose_with_cov.pose);
      // transform covariance, only the frame difference
      pose_with_cov.covariance =
        tf2::transformCovariance(pose_with_cov.covariance, tf_target2objects_world);
    }
  }
  return true;
}

[[maybe_unused]] inline boost::optional<geometry_msgs::msg::Transform> getTransform(
  const tf2_ros::Buffer & tf_buffer, const std::string & source_frame_id,
  const std::string & target_frame_id, const rclcpp::Time & time)
{
  try {
    geometry_msgs::msg::TransformStamped self_transform_stamped;
    self_transform_stamped = tf_buffer.lookupTransform(
      target_frame_id, source_frame_id, time, rclcpp::Duration::from_seconds(0.5));
    return self_transform_stamped.transform;
  } catch (tf2::TransformException & ex) {
    RCLCPP_WARN_STREAM(rclcpp::get_logger("object_recognition_utils"), ex.what());
    return boost::none;
  }
}

DetectedObjects toDetectedObjects(const TrackedObjects & tracked_objects)
{
  DetectedObjects detected_objects;
  detected_objects.header = tracked_objects.header;

  detected_objects.objects.reserve(tracked_objects.objects.size());
  for (const auto & tracked_object : tracked_objects.objects) {
    detected_objects.objects.emplace_back(toDetectedObject(tracked_object));
  }
  return detected_objects;
}

DetectedObject toDetectedObject(const TrackedObject & tracked_object)
{
  DetectedObject detected_object;
  detected_object.existence_probability = tracked_object.existence_probability;

  detected_object.classification = tracked_object.classification;

  detected_object.kinematics.pose_with_covariance = tracked_object.kinematics.pose_with_covariance;
  detected_object.kinematics.has_position_covariance = true;
  detected_object.kinematics.orientation_availability =
    tracked_object.kinematics.orientation_availability;
  detected_object.kinematics.twist_with_covariance =
    tracked_object.kinematics.twist_with_covariance;
  detected_object.kinematics.has_twist = true;
  detected_object.kinematics.has_twist_covariance = true;

  detected_object.shape = tracked_object.shape;
  return detected_object;
}

void DetectionByTracker::mergeOverSegmentedObjects(
  const autoware_perception_msgs::msg::DetectedObjects & tracked_objects,
  const tier4_perception_msgs::msg::DetectedObjectsWithFeature & in_cluster_objects,
  autoware_perception_msgs::msg::DetectedObjects & out_no_found_tracked_objects,
  tier4_perception_msgs::msg::DetectedObjectsWithFeature & out_objects)
{
  constexpr float precision_threshold = 0.5;
  out_objects.header = in_cluster_objects.header;
  out_no_found_tracked_objects.header = tracked_objects.header;

  for (const auto & tracked_object : tracked_objects.objects) {
    const auto & label = tracked_object.classification.front().label;
    if (tracker_ignore_.isIgnore(label)) continue;

    // change search range according to label type
    const float max_search_range = max_search_distance_for_merger_[label];

    // extend shape
    autoware_perception_msgs::msg::DetectedObject extended_tracked_object = tracked_object;
    extended_tracked_object.shape = extendShape(tracked_object.shape, /*scale*/ 1.1);

    pcl::PointCloud<pcl::PointXYZ> pcl_merged_cluster;
    for (const auto & initial_object : in_cluster_objects.feature_objects) {
      const float distance = autoware_utils::calc_distance2d(
        tracked_object.kinematics.pose_with_covariance.pose,
        initial_object.object.kinematics.pose_with_covariance.pose);

      if (max_search_range < distance) {
        continue;
      }

      // If there is an initial object in the tracker, it will be merged.
      const float precision = autoware::object_recognition_utils::get2dPrecision(
        initial_object.object, extended_tracked_object);
      if (precision < precision_threshold) {
        continue;
      }
      pcl::PointCloud<pcl::PointXYZ> pcl_cluster;
      pcl::fromROSMsg(initial_object.feature.cluster, pcl_cluster);
      pcl_merged_cluster += pcl_cluster;
    }

    if (pcl_merged_cluster.points.empty()) {  // if clusters aren't found
      out_no_found_tracked_objects.objects.push_back(tracked_object);
      continue;
    }

    // build output clusters
    tier4_perception_msgs::msg::DetectedObjectWithFeature feature_object;
    feature_object.object.classification = tracked_object.classification;

    bool is_shape_estimated = shape_estimator_->estimateShapeAndPose(
      label, pcl_merged_cluster,
      getReferenceYawInfo(
        label, tf2::getYaw(tracked_object.kinematics.pose_with_covariance.pose.orientation)),
      getReferenceShapeSizeInfo(label, tracked_object.shape),
      tracked_object.kinematics.pose_with_covariance.pose, feature_object.object.shape,
      feature_object.object.kinematics.pose_with_covariance.pose);
    if (!is_shape_estimated) {
      out_no_found_tracked_objects.objects.push_back(tracked_object);
      continue;
    }

    feature_object.object.existence_probability =
      autoware::object_recognition_utils::get2dIoU(tracked_object, feature_object.object);
    setClusterInObjectWithFeature(in_cluster_objects.header, pcl_merged_cluster, feature_object);
    out_objects.feature_objects.push_back(feature_object);
  }
}

autoware_perception_msgs::msg::Shape extendShape(
  const autoware_perception_msgs::msg::Shape & shape, const float scale)
{
  autoware_perception_msgs::msg::Shape output = shape;
  output.dimensions.x *= scale;
  output.dimensions.y *= scale;
  output.dimensions.z *= scale;
  for (auto & point : output.footprint.points) {
    point.x *= scale;
    point.y *= scale;
    point.z *= scale;
  }
  return output;
}

double get2dPrecision(const T1 & source_object, const T2 & target_object)
{
  const auto source_polygon = autoware_utils_geometry::to_polygon2d(source_object);
  const double source_area = boost::geometry::area(source_polygon);
  if (source_area < MIN_AREA) return 0.0;
  const auto target_polygon = autoware_utils_geometry::to_polygon2d(target_object);
  if (boost::geometry::area(target_polygon) < MIN_AREA) return 0.0;

  const double intersection_area = getIntersectionArea(source_polygon, target_polygon);
  if (intersection_area < MIN_AREA) return 0.0;

  return std::min(1.0, intersection_area / source_area);
}

Polygon2d to_polygon2d(
  const geometry_msgs::msg::Pose & pose, const autoware_perception_msgs::msg::Shape & shape)
{
  Polygon2d polygon;

  if (shape.type == autoware_perception_msgs::msg::Shape::BOUNDING_BOX) {
    const auto point0 = autoware_utils_geometry::calc_offset_pose(
                          pose, shape.dimensions.x / 2.0, shape.dimensions.y / 2.0, 0.0)
                          .position;
    const auto point1 = autoware_utils_geometry::calc_offset_pose(
                          pose, -shape.dimensions.x / 2.0, shape.dimensions.y / 2.0, 0.0)
                          .position;
    const auto point2 = autoware_utils_geometry::calc_offset_pose(
                          pose, -shape.dimensions.x / 2.0, -shape.dimensions.y / 2.0, 0.0)
                          .position;
    const auto point3 = autoware_utils_geometry::calc_offset_pose(
                          pose, shape.dimensions.x / 2.0, -shape.dimensions.y / 2.0, 0.0)
                          .position;

    append_point_to_polygon(polygon, point0);
    append_point_to_polygon(polygon, point1);
    append_point_to_polygon(polygon, point2);
    append_point_to_polygon(polygon, point3);
  } else if (shape.type == autoware_perception_msgs::msg::Shape::CYLINDER) {
    const double radius = shape.dimensions.x / 2.0;
    constexpr int circle_discrete_num = 6;
    for (int i = 0; i < circle_discrete_num; ++i) {
      geometry_msgs::msg::Point point;
      point.x = std::cos(
                  (static_cast<double>(i) / static_cast<double>(circle_discrete_num)) * 2.0 * M_PI +
                  M_PI / static_cast<double>(circle_discrete_num)) *
                  radius +
                pose.position.x;
      point.y = std::sin(
                  (static_cast<double>(i) / static_cast<double>(circle_discrete_num)) * 2.0 * M_PI +
                  M_PI / static_cast<double>(circle_discrete_num)) *
                  radius +
                pose.position.y;
      append_point_to_polygon(polygon, point);
    }
  } else if (shape.type == autoware_perception_msgs::msg::Shape::POLYGON) {
    const double poly_yaw = tf2::getYaw(pose.orientation);
    const auto rotated_footprint = rotate_polygon(shape.footprint, poly_yaw);
    for (const auto rel_point : rotated_footprint.points) {
      geometry_msgs::msg::Point abs_point;
      abs_point.x = pose.position.x + rel_point.x;
      abs_point.y = pose.position.y + rel_point.y;

      append_point_to_polygon(polygon, abs_point);
    }
  } else {
    throw std::logic_error("The shape type is not supported in autoware_utils.");
  }

  // NOTE: push back the first point in order to close polygon
  if (!polygon.outer().empty()) {
    append_point_to_polygon(polygon, polygon.outer().front());
  }

  return is_clockwise(polygon) ? polygon : inverse_clockwise(polygon);
}

void append_point_to_polygon(Polygon2d & polygon, const geometry_msgs::msg::Point & geom_point)
{
  Point2d point;
  point.x() = geom_point.x;
  point.y() = geom_point.y;

  bg::append(polygon.outer(), point);
}

geometry_msgs::msg::Polygon rotate_polygon(
  const geometry_msgs::msg::Polygon & polygon, const double & angle)
{
  const double cos = std::cos(angle);
  const double sin = std::sin(angle);
  geometry_msgs::msg::Polygon rotated_polygon;
  for (const auto & point : polygon.points) {
    auto rotated_point = point;
    rotated_point.x = cos * point.x - sin * point.y;
    rotated_point.y = sin * point.x + cos * point.y;
    rotated_polygon.points.push_back(rotated_point);
  }
  return rotated_polygon;
}

bool is_clockwise(const Polygon2d & polygon)
{
  const int n = polygon.outer().size();
  const double x_offset = polygon.outer().at(0).x();
  const double y_offset = polygon.outer().at(0).y();
  double sum = 0.0;
  for (std::size_t i = 0; i < polygon.outer().size(); ++i) {
    sum +=
      (polygon.outer().at(i).x() - x_offset) * (polygon.outer().at((i + 1) % n).y() - y_offset) -
      (polygon.outer().at(i).y() - y_offset) * (polygon.outer().at((i + 1) % n).x() - x_offset);
  }

  return sum < 0.0;
}

Polygon2d inverse_clockwise(const Polygon2d & polygon)
{
  auto output_polygon = polygon;
  boost::geometry::reverse(output_polygon);
  return output_polygon;
}

inline double getIntersectionArea(
  const Polygon2d & source_polygon, const Polygon2d & target_polygon)
{
  std::vector<Polygon2d> intersection_polygons;
  boost::geometry::intersection(source_polygon, target_polygon, intersection_polygons);
  return getSumArea(intersection_polygons);
}

inline double getSumArea(const std::vector<Polygon2d> & polygons)
{
  return std::accumulate(
    polygons.begin(), polygons.end(), 0.0,
    [](double acc, const Polygon2d & p) { return acc + boost::geometry::area(p); });
}

bool ShapeEstimator::estimateShapeAndPose(
  const uint8_t label, const pcl::PointCloud<pcl::PointXYZ> & cluster,
  const boost::optional<ReferenceYawInfo> & ref_yaw_info,
  const boost::optional<ReferenceShapeSizeInfo> & ref_shape_size_info,
  const boost::optional<geometry_msgs::msg::Pose> & ref_pose,
  autoware_perception_msgs::msg::Shape & shape_output, geometry_msgs::msg::Pose & pose_output)
{
  autoware_perception_msgs::msg::Shape shape;
  geometry_msgs::msg::Pose pose;
  // estimate shape
  bool reverse_to_unknown = false;
  if (!estimateOriginalShapeAndPose(label, cluster, ref_yaw_info, shape, pose)) {
    reverse_to_unknown = true;
  }

  // rule based filter
  if (use_filter_) {
    if (!applyFilter(label, shape, pose)) {
      reverse_to_unknown = true;
    }
  }

  // rule based corrector
  if (use_corrector_) {
    bool use_reference_yaw = ref_yaw_info ? true : false;
    if (!applyCorrector(label, use_reference_yaw, ref_shape_size_info, ref_pose, shape, pose)) {
      reverse_to_unknown = true;
    }
  }
  if (reverse_to_unknown) {
    estimateOriginalShapeAndPose(Label::UNKNOWN, cluster, ref_yaw_info, shape, pose);
    shape_output = shape;
    pose_output = pose;
    return false;
  }
  shape_output = shape;
  pose_output = pose;
  return true;
}

bool ShapeEstimator::estimateOriginalShapeAndPose(
  const uint8_t label, const pcl::PointCloud<pcl::PointXYZ> & cluster,
  const boost::optional<ReferenceYawInfo> & ref_yaw_info,
  autoware_perception_msgs::msg::Shape & shape_output, geometry_msgs::msg::Pose & pose_output)
{
  // estimate shape
  std::unique_ptr<model::ShapeEstimationModelInterface> model_ptr;
  if (
    label == Label::CAR || label == Label::TRUCK || label == Label::BUS ||
    label == Label::TRAILER || label == Label::MOTORCYCLE || label == Label::BICYCLE) {
    model_ptr.reset(new model::BoundingBoxShapeModel(ref_yaw_info, use_boost_bbox_optimizer_));
  } else if (label == Label::PEDESTRIAN) {
    model_ptr.reset(new model::CylinderShapeModel());
  } else {
    model_ptr.reset(new model::ConvexHullShapeModel());
  }

  return model_ptr->estimate(cluster, shape_output, pose_output);
}

  virtual bool estimate(
    const pcl::PointCloud<pcl::PointXYZ> & cluster,
    autoware_perception_msgs::msg::Shape & shape_output,
    geometry_msgs::msg::Pose & pose_output) = 0;
};

}  // namespace model
}  // namespace autoware::shape_estimation

class BoundingBoxShapeModel : public ShapeEstimationModelInterface
{
private:
  bool fitLShape(
    const pcl::PointCloud<pcl::PointXYZ> & cluster, const float min_angle, const float max_angle,
    autoware_perception_msgs::msg::Shape & shape_output, geometry_msgs::msg::Pose & pose_output);
  float calcClosenessCriterion(const std::vector<float> & C_1, const std::vector<float> & C_2);
  float optimize(
    const pcl::PointCloud<pcl::PointXYZ> & cluster, const float min_angle, const float max_angle);
  float boostOptimize(
    const pcl::PointCloud<pcl::PointXYZ> & cluster, const float min_angle, const float max_angle);

public:
  BoundingBoxShapeModel();
  explicit BoundingBoxShapeModel(
    const boost::optional<ReferenceYawInfo> & ref_yaw_info, bool use_boost_bbox_optimizer = false);
  boost::optional<ReferenceYawInfo> ref_yaw_info_;
  bool use_boost_bbox_optimizer_;

  ~BoundingBoxShapeModel() {}

  bool estimate(
    const pcl::PointCloud<pcl::PointXYZ> & cluster,
    autoware_perception_msgs::msg::Shape & shape_output,
    geometry_msgs::msg::Pose & pose_output) override;
};

}  // namespace model
}  // namespace autoware::shape_estimation

